/**
 * Static visa data - all text inline with full i18n support.
 * Each record carries its own text in all 10 languages so components
 * can render directly without any i18n key resolution.
 *
 * Language keys: cn, tw, en, ja, ko, ru, fr, es, de, it
 */

export type LangKey = 'cn' | 'tw' | 'en' | 'ja' | 'ko' | 'ru' | 'fr' | 'es' | 'de' | 'it';

export interface MultiLang {
  cn: string; tw: string; en: string; ja: string; ko: string;
  ru: string; fr: string; es: string; de: string; it: string;
}

export interface StaticVisaType {
  code: string;
  name: MultiLang;
  description: MultiLang;
  sortOrder: number;
}

export interface StaticVisaDocument {
  visaCode: string;
  section: 'general' | 'special';
  icon: string;
  title: MultiLang;
  description: MultiLang;
  linkUrl?: string;
  sortOrder: number;
  isRequired: boolean;
}

export interface StaticVisaFee {
  visaCode: string;
  purpose: MultiLang;
  feeRange: string;
  note: MultiLang;
  sortOrder: number;
}

export interface StaticVisaPhotoText {
  pageTitle: MultiLang;
  generalReq: MultiLang;
  generalReqDesc: MultiLang;
  photoDimensions: MultiLang;
  photoDimensionsDesc: MultiLang;
  faceReq: MultiLang;
  faceReqDesc: MultiLang;
  headwearReq: MultiLang;
  headwearReqDesc: MultiLang;
  digitalReq: MultiLang;
  digitalReqDesc: MultiLang;
  digitalNote: MultiLang;
  dimensionLabel: MultiLang;
  dimensionLabel2: MultiLang;
  photoSize: MultiLang;
  qualifiedExample: MultiLang;
  unqualifiedTitle: MultiLang;
  unqualifiedExample: MultiLang;
  dimensionIllustration: MultiLang;
}

export interface StaticVisaCardStep {
  title: MultiLang;
  desc: MultiLang;
  image: string;
  links?: { name: MultiLang; url: string }[];
}

export interface StaticVisaCardText {
  pageTitle: MultiLang;
  steps: StaticVisaCardStep[];
}

export interface StaticVisaDownloadText {
  pageTitle: MultiLang;
  fileName: MultiLang;
  action: MultiLang;
  view: MultiLang;
  docs: { title: MultiLang; url: string }[];
}

export interface StaticVisaFormText {
  pageTitle: MultiLang;
}

// Helper to create MultiLang objects concisely
function ml(cn: string, en: string, ja?: string, ko?: string, ru?: string, fr?: string, es?: string, de?: string, it?: string, tw?: string): MultiLang {
  return { cn, tw: tw || cn, en, ja: ja || en, ko: ko || en, ru: ru || en, fr: fr || en, es: es || en, de: de || en, it: it || en };
}

